payload.message:
Run the daily specialist-agent bench health check.

Execute exactly:
set -euo pipefail
OUT="$(python3 - <<'PY'
import json, subprocess, pathlib, sys
expected = ['main','samantha','sentinel','shipwright','caretaker','archivist','scout','operator','reviewer','builder-mobile']
opus_specialists = ['sentinel','shipwright','caretaker','archivist','scout','operator','reviewer','builder-mobile']
issues=[]

raw = subprocess.check_output(['openclaw','config','get','agents.list'], text=True)
agents = json.loads(raw)
by_id = {a.get('id'): a for a in agents}

for aid in expected:
    if aid not in by_id:
        issues.append(f'missing-agent:{aid}')

for aid in expected:
    if aid not in by_id:
        continue
    a=by_id[aid]
    ws = pathlib.Path(a.get('workspace') or '/Users/sawyer/.openclaw/workspace')
    for f in ['SOUL.md','AGENTS.md','IDENTITY.md','CLAUDE.md']:
        if not (ws/f).exists():
            issues.append(f'missing-file:{aid}:{f}')

s = by_id.get('samantha')
if s:
    m = s.get('model', {})
    if m.get('primary') != 'openai-codex/gpt-5.3-codex':
        issues.append('model-mismatch:samantha:primary')
    fb = m.get('fallbacks') or []
    if 'anthropic/claude-opus-4-6' not in fb:
        issues.append('model-mismatch:samantha:fallback')

for aid in opus_specialists:
    a = by_id.get(aid)
    if not a:
        continue
    m = a.get('model', {})
    if m.get('primary') != 'anthropic/claude-opus-4-6':
        issues.append(f'model-mismatch:{aid}:primary')
    fb = m.get('fallbacks') or []
    if 'openai-codex/gpt-5.3-codex' not in fb:
        issues.append(f'model-mismatch:{aid}:fallback')

if issues:
    print('FAIL')
    for i in issues:
        print(i)
    sys.exit(2)

print('OK: agent bench config + workspace files validated')
PY
)" || RC=$?
RC=${RC:-0}

if [ "$RC" -ne 0 ]; then
  MSG="$(printf '%s' "$OUT" | tail -n 30 | tr '\n' '; ' | sed 's/"//g')"
  openclaw system event --text "Reminder: daily agent bench health check found issues. ${MSG}" --mode now
  exit 1
fi

openclaw agents list --bindings >/tmp/agent-bench-list.txt
exit 0
